using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using System.Data.SqlClient;
using System.Text.RegularExpressions;

namespace MyApp.Controllers
{
    public class ProductController : Controller
    {
        private readonly string _connectionString = "Server=myserver;Database=mydatabase;User ID=myuser;Password=mypassword";

        // GET: Product/Details/5
        public ActionResult Details(int id)
        {
            var product = new Product();
            using (var connection = new SqlConnection(_connectionString))
            {
                connection.Open();
                var command = new SqlCommand("SELECT * FROM Products WHERE Id = @Id", connection);
                command.Parameters.AddWithValue("@Id", id);
                var reader = command.ExecuteReader();
                while (reader.Read())
                {
                    product.Name = reader["Name"].ToString();
                    product.Description = reader["Description"].ToString();
                    product.Price = Convert.ToDecimal(reader["Price"]);
                }
            }
            return View(product);
        }

        // POST: Product/Details/5
        [HttpPost]
        public ActionResult Details(int id, FormCollection form)
        {
            var product = new Product();
            using (var connection = new SqlConnection(_connectionString))
            {
                connection.Open();
                var command = new SqlCommand("SELECT * FROM Products WHERE Id = @Id", connection);
                command.Parameters.AddWithValue("@Id", id);
                var reader = command.ExecuteReader();
                while (reader.Read())
                {
                    product.Name = reader["Name"].ToString();
                    product.Description = reader["Description"].ToString();
                    product.Price = Convert.ToDecimal(reader["Price"]);
                }
            }

            // Check if the user has submitted a review
            var reviewSubmitted = false;
            foreach (var key in form.AllKeys)
            {
                if (key == "Review")
                {
                    reviewSubmitted = true;
                    break;
                }
            }

            // If a review was submitted, save it to the database
            if (reviewSubmitted)
            {
                var review = new Review();
                review.ProductId = id;
                review.UserId = User.Identity.Name;
                review.ReviewText = form["Review"];
                using (var connection = new SqlConnection(_connectionString))
                {
                    connection.Open();
                    var command = new SqlCommand("INSERT INTO Reviews (ProductId, UserId, ReviewText) VALUES (@ProductId, @UserId, @ReviewText)", connection);
                    command.Parameters.AddWithValue("@ProductId", id);
                    command.Parameters.AddWithValue("@UserId", User.Identity.Name);
                    command.Parameters.AddWithValue("@ReviewText", review.ReviewText);
                    command.ExecuteNonQuery();
                }
            }

            return View(product);
        }
    }
}